var e=[{id:`L3_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`저리 비켜, 이 망할 침식체가!!`,JPN:`退け、くそったれの侵食体め！！`,ENG:`Get out of the way, darn Corrupted Objects!!`,TWN:`走開！該死的侵蝕體！！`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`후우…… 흐으…… 으읏……!`,JPN:`ふう……くぅ……うぅ……！`,ENG:`Phew... Urgh... Ngh...!`,TWN:`呼呼……呼……呃……！`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:{char_id:`OLD_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L11_1`,type:`dialog`,speaker:`OLD_GRONIA_NULL_NULL`,text:{KOREA:`손님……. 왜 그래……?`,JPN:`お客さん……どうしたの……？`,ENG:`My dear guest... What’s the matter...?`,TWN:`客人……你還好嗎……？`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:{char_id:`OLD_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L12_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`알면서 물어보는 거죠?! 이대로면 다 죽게 생겼으니까 그러죠!`,JPN:`わざとですよね！？　このままじゃみんな死ぬことになるからですよ！`,ENG:`You already know, right? We’re all going to die if this keeps up!`,TWN:`你是明知故問嗎？！我不這樣的話，就是大家一起死！`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:{char_id:`OLD_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L14_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`그렇다면 도망쳐. 중사님.`,JPN:`だったら逃げなさい、軍曹。`,ENG:`Then feel free to run away, Sergeant.`,TWN:`中士，你們快逃吧！`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`손짓 한 번으로 도시 구획 하나를 지워 버리는 상대야. 도망친다고 나무랄 사람 아무도 없어.`,JPN:`手を一振りしただけで都市の区画一つを消してしまう相手よ。逃げたって誰も責めないの。`,ENG:`Our enemy can wipe out an entire city block with a flick of the wrist. No one could blame you for running away.`,TWN:`對方可是彈指之間就能毀掉整座城市，就算你逃走也沒人會怪你的！`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`도망은……!`,JPN:`逃げるなんて……！`,ENG:`Running away...!`,TWN:`逃走……！`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`귀관의 공헌에 감사합니다.`,JPN:`貴官の貢献に感謝します。`,ENG:`Thank you for all you’ve done.`,TWN:`謝謝中士的貢獻。`},stage:{bg:`HARMONY_03`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`귀관이 아니었으면…… 이 풍경은 볼 수 없었을 겁니다.`,JPN:`貴官がいなかったら……この景色を見ることは叶いませんでした。`,ENG:`If it weren’t for you... We never would have been able to witness this moment.`,TWN:`因為中士……才能看到這樣的場景。`},stage:{bg:`HARMONY_03`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`그런 말을 듣고 어떻게 도망쳐요……!`,JPN:`そんなことを聞いて逃げられるわけがないでしょ……！`,ENG:`How can I run after hearing something like that...!`,TWN:`說這種話叫我怎麼逃……！`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_ON`,text:{KOREA:`호오…….`,JPN:`ほう……`,ENG:`Ooh...`,TWN:`呵……`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_ON`,face:`UNIT_SURPRISE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_ON`,text:{KOREA:`그러고 보니 귀가 좋은 아이가 있었죠.`,JPN:`そういえば、音感がいい子がいましたね。`,ENG:`Now that I think of it, there was a kid with a good ear.`,TWN:`差點忘記有個聽力很好的女生呢。`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_ON`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_ON`,text:{KOREA:`어디 단원으로 삼기에 적합한지 시험해 볼까요?`,JPN:`団員としてふさわしいか、試してみましょうか？`,ENG:`Shall we see which unit you are most suitable for?`,TWN:`來測試看看你有沒有當團員的資格吧？`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_ON`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_ON`,text:{KOREA:`실패작이 한 번 상쇄시켰으니, 이번에는 조금 더 정교한 소리를 자아내 드리죠.`,JPN:`失敗作に一回相殺されましたので、今回はもっと精巧な音を紡いでさしあげましょう。`,ENG:`Well, the failed product offset my first attempt, so let us make a more sophisticated sound.`,TWN:`失敗品剛才將我的聲音抵銷掉，那這次就來個更美妙的聲音吧？`},stage:{bg:`COUNTERSIDE_COLLAPSE`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_ON`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};